import styled from 'styled-components';

import GlobalStyle from './GlobalStyles';
import LandingPage from './components/LandingPage/'

const App = () => {
  return (
    <AppContainer>
      <GlobalStyle />

      <LandingPage id="Home" />
      <div id="About" style={{ 
        background: "white",
        width: "100vw",
        height: "100vh"
      }}>
        ABOUT
      </div>
    </AppContainer>
  );
}

const AppContainer = styled.div``

export default App;
